typedef uint32_t u32; typedef uint64_t u64; typedef uint8_t u8;

static u32 expand(u32 k){ k&=0xFFFFF; return k ^ (k<<16) ^ (k*12345u); }

static u8 g_function(u8 a,u8 b,u8 x){ u8 t=(u8)(a+b+x); return (u8)((t<<2)|(t>>6)); }
static u8 ror2(u8 y){ return (u8)((y>>2)|(y<<6)); }

static u32 f_function(u32 v){
 u8 x[4],y[4];
 for(int i=0;i<4;i++){ x[i]=v&0xFF; v>>=8; }
 y[2]=g_function(x[3]^x[2], x[1]^x[0], 1);
 y[3]=g_function(x[3], y[2], 0);
 y[1]=g_function(x[1]^x[0], y[2], 0);
 y[0]=g_function(x[0], y[1], 1);
 u32 o=0; for(int i=0;i<4;i++) o|=(u32)y[i]<<(8*i); return o;
}
// invert f: given output, recover input
static u32 finv(u32 out){
 u8 y0=out&0xff, y1=(out>>8)&0xff, y2=(out>>16)&0xff, y3=(out>>24)&0xff;
 u8 s0=ror2(y0), s1=ror2(y1), s2=ror2(y2), s3=ror2(y3);
 u8 x1x0=(u8)(s1 - y2);
 u8 x0=(u8)(s0 - y1 - 1);
 u8 x1=x0 ^ x1x0;
 u8 x3=(u8)(s3 - y2);
 u8 x3x2=(u8)(s2 - x1x0 - 1);
 u8 x2=x3 ^ x3x2;
 return (u32)x0 | ((u32)x1<<8) | ((u32)x2<<16) | ((u32)x3<<24);
}

static u32 getleft(u64 x){ return (x>>32)&0xFFFFFFFF; }
static u32 getright(u64 x){ return x&0xFFFFFFFF; }
static u64 merge(u32 l,u32 r){ return ((u64)l<<32)|r; }

static u32 KEY[4];
static u64 encrypt(u64 pt){
 u32 left=getleft(pt), right=getright(pt);
 right^=left;
 for(int r=0;r<4;r++){ u32 mixed=f_function(right^KEY[r]); u32 t=right; right=left^mixed; left=t; }
 left^=right; return merge(right,left);
}
static u64 decrypt(u64 ct){
 u32 left=getright(ct), right=getleft(ct);
 left^=right;
 for(int r=3;r>=0;r--){ u32 t=left; left=right; u32 mixed=f_function(t^KEY[r]); right=t; left^=mixed; }
 right^=left; return merge(left,right);
}

